import { Shield, Brain, Globe, Network, Code2, Database } from 'lucide-react';
import SectionHeader from './SectionHeader';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';

export default function About() {
  const { dark, lang } = useApp();
  const tr = t[lang];
  const bg = dark ? 'bg-[#13131e]' : 'bg-cream';
  const cardBg = dark ? 'bg-[#1a1a28]' : 'bg-parchment';
  const textMuted2 = dark ? 'text-white/60' : 'text-muted2';
  const textStrong = dark ? 'text-white font-semibold' : 'text-ink2 font-semibold';

  const skills = [
    { icon: <Shield size={18}/>, key: 'cyber' },
    { icon: <Brain size={18}/>, key: 'ai' },
    { icon: <Network size={18}/>, key: 'net' },
    { icon: <Globe size={18}/>, key: 'web' },
    { icon: <Code2 size={18}/>, key: 'code' },
    { icon: <Database size={18}/>, key: 'db' },
  ];

  return (
    <section id="about" className={`py-24 px-[5%] ${bg} transition-colors duration-300`}>
      <SectionHeader tag={tr.aboutTag} title={tr.aboutTitle} />
      <div className="grid md:grid-cols-2 gap-16 items-start">
        <div className="reveal space-y-5">
          <p className={`text-[1.05rem] leading-[1.95] ${textMuted2}`}>
            {tr.aboutP1.split('Kareem Basem').map((part, i) =>
              i === 0 ? part : <span key={i}><strong className={textStrong}>Kareem Basem</strong>{part}</span>
            )}
          </p>
          <p className={`text-[0.95rem] leading-[1.85] ${textMuted2}`}>{tr.aboutP2}</p>
          <div className="inline-flex items-center gap-2 bg-amber/10 border border-amber/20 px-4 py-2 rounded-full text-xs font-semibold text-amber2">
            {tr.scoutBadge}
          </div>
        </div>
        <div className="reveal delay-2 grid grid-cols-2 gap-3">
          {skills.map(s => (
            <div key={s.key}
              className={`flex items-center gap-3 px-4 py-3.5 ${cardBg} rounded-xl border-[1.5px] border-transparent shadow-sm transition-all duration-200 hover:border-amber/30 hover:translate-x-1.5 hover:shadow-md cursor-default`}>
              <span className="text-amber flex-shrink-0">{s.icon}</span>
              <span className={`text-sm font-medium ${dark ? 'text-white/80' : 'text-ink2'}`}>{tr.skills[s.key]}</span>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
